public void init()
{
    next init();
    this.applyExchangeRateFreeze();
}

private void applyExchangeRateFreeze()
{


        boolean freeze = ETGCanadaParametersHelper1::isExchangeRateFrozen();


        FormControl exchRateCtrl =this.design().controlName(identifierStr(editExchRate));

        FormControl repExchRateCtrl =this.design().controlName(identifierStr(editReportingCurrencyExchRate));


        if (freeze)
        {

            exchRateCtrl.allowEdit(false);

            repExchRateCtrl.allowEdit(false);
        }

}
